import { Controller, Get, Param, Query, UseGuards } from '@nestjs/common';
import { ApiSecurity, ApiTags } from '@nestjs/swagger';
import {
  ApiKeyGuard,
  RequireApiKey,
} from '../../../../common/guards/api-key.guard';
import { AnalyticsService } from '../../application/services/analytics.service';

/**
 * B2B analytics endpoints (README §2.4 / §2.8 Workflow 2 consumption).
 * Authenticated by a B2B API Key (NOT JWT) — README §2.5 Authorization.
 */
@ApiTags('analytics')
@ApiSecurity('api-key')
@Controller('analytics')
@UseGuards(ApiKeyGuard)
@RequireApiKey('B2B')
export class AnalyticsController {
  constructor(private readonly analytics: AnalyticsService) {}

  @Get('segments')
  getSegments(@Query('storeId') storeId?: string) {
    return this.analytics.getSegmentDistribution(storeId);
  }

  @Get('products/:id/insights')
  getProductInsights(@Param('id') id: string) {
    return this.analytics.getProductInsights(id);
  }

  @Get('stores/:id/overview')
  getStoreOverview(@Param('id') id: string) {
    return this.analytics.getStoreOverview(id);
  }
}
